/**
 * @summary List job requirements
 */
export const getListJobRequirementsUrl = (
  params?: ListJobRequirementsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/job-requirements?${stringifiedParams}`
    : `/api/job-requirements`;
};

export const listJobRequirements = async (
  params?: ListJobRequirementsParams,
  options?: RequestInit,
): Promise<JobRequirement[]> => {
  return customFetch<JobRequirement[]>(getListJobRequirementsUrl(params), {
    ...options,
    method: "GET",
  });
};

